#include<bits/stdc++.h>
using namespace std;
double x[21],y[21];
int t,n,m,l[21][21],lowunbit[(1<<20)],dp[(1<<20)];
void calc(double &x,double &y,double a1,double b1,double c1,double a2,double b2,double c2)
{
    y=(a1*c2-a2*c1)/(a1*b2-a2*b1);
    x=(c1-b1*y)/a1;
}
int main()
{
    for(int i=0;i<(1<<18);i++)
    {
        int j=1;
        while(j<=18&&i&(1<<(j-1)))
        {
            j++;
        }
        lowunbit[i]=j;
    }
    int t;
    scanf("%d",&t);
    while(t--)
    {
        memset(l,0,sizeof(l));
        memset(dp,0x3f,sizeof(dp));
        dp[0]=0;
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n;i++)
        {
            scanf("%lf%lf",&x[i],&y[i]);
        }
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                if(abs(x[i]-x[j])<(1e-8))
                {
                    continue;
                }
                double a,b;
                calc(a,b,x[i]*x[i],x[i],y[i],x[j]*x[j],x[j],y[j]);
                if(a>(-(1e-8)))
                {
                    continue;
                }
                for(int k=1;k<=n;k++)
                {
                    if(abs(a*x[k]*x[k]+b*x[k]-y[k])<(1e-8))
                    {
                        l[i][j]|=(1<<(k-1));
                    }
                }
            }
        }
        for(int i=0;i<(1<<n);i++)
        {
            int j=lowunbit[i];
            dp[i|(1<<(j-1))]=min(dp[i|(1<<(j-1))],dp[i]+1);
            for(int k=1;k<=n;k++)
            {
                dp[i|l[j][k]]=min(dp[i|l[j][k]],dp[i]+1);
            }
        }
        printf("%d\n",dp[(1<<n)-1]);
    }
    return 0;
}
